  24→const extractBearerToken = (authHeader = "") => {
  25→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
  26→    if (!trimmed) return "";
  27→
  28→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
  29→    if (bearerMatch?.[1]) {
  30→        return bearerMatch[1].trim();
  31→    }
  32→
  33→    return trimmed;
  34→};
  35→
  36→const resolveAuthUser = async (token) => {
  37→    if (!token) {
  38→        return { user: null, error: null };
  39→    }
  40→
  41→    const { data: authData, error: authError } = await supabase.auth.getUser(token);
  42→    if (authError || !authData?.user?.id) {
  43→        return { user: null, error: authError || new Error("missing user id") };
  44→    }
  45→
  46→    return { user: authData.user, error: null };
  47→};
  48→
  49→const requireAuth = async (req, res, next) => {
  50→    const token = extractBearerToken(req.headers?.authorization);
  51→    if (!token) {
  52→        return res.status(401).json({ error: 'not authorized' });
  53→    }
  54→
  55→    const { user, error } = await resolveAuthUser(token);
  56→    if (error || !user?.id) {
  57→        console.error('auth middleware error:', error?.message || 'missing user id');
  58→        return res.status(401).json({ error: 'not authorized' });
  59→    }
  60→
  61→    req.userId = user.id;
  62→    req.authUser = user;
  63→    return next();
  64→};
  65→
  66→const optionalAuth = async (req, _res, next) => {
  67→    const token = extractBearerToken(req.headers?.authorization);
  68→    if (!token) {
  69→        return next();
  70→    }
  71→
  72→    const { user } = await resolveAuthUser(token);
  73→    if (user?.id) {
  74→        req.userId = user.id;
  75→        req.authUser = user;
  76→    }
  77→
  78→    return next();
  79→};
