 91→const validateStickyPayload = (payload) => {
 92→    if(!isPlainObject(payload)){
 93→        throw {status: 400, error: 'sticky payload should be an object'};
 94→    }
 95→
 96→    const text = typeof payload.text === 'string' ? payload.text.trim() : '';
 97→    if(!text){
 98→        throw {status: 400, error: 'sticky text is required'};
 99→    }
100→    if(text.length > MAX_STICKY_TEXT_LENGTH){
101→        throw {status: 400, error: `sticky text should be less than ${MAX_STICKY_TEXT_LENGTH + 1} characters`};
102→    }
103→
104→    const x = parseNumberInRange(payload.x, 'sticky x');
105→    const y = parseNumberInRange(payload.y, 'sticky y');
106→    const color = typeof payload.color === 'string' && payload.color.trim()
107→        ? payload.color.trim().slice(0, 32)
108→        : '#fff4a8';
109→
110→    return {
111→        text: text,
112→        x: x,
113→        y: y,
114→        color: color
115→    };
116→}
