  47→const createOptimisticId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  48→const toTimestamp = (value) => {
  49→    const parsed = Date.parse(value || "");
  50→    return Number.isNaN(parsed) ? 0 : parsed;
  51→};
  52→const sortByCreatedAt = (a, b) => {
  53→    const byDate = toTimestamp(a?.created_at) - toTimestamp(b?.created_at);
  54→    if(byDate !== 0){
  55→        return byDate;
  56→    }
  57→    return String(a?.id || "").localeCompare(String(b?.id || ""));
  58→};
  59→const sanitizeNormalizedPoints = (rawPoints) => {
  60→    if(!Array.isArray(rawPoints)){
  61→        return [];
  62→    }
  63→
  64→    const numericPoints = rawPoints
  65→        .map((point) => Number(point))
  66→        .filter((point) => !Number.isNaN(point))
  67→        .map((point) => clamp(point, 0, 1));
  68→
  69→    if(numericPoints.length < 2){
  70→        return [];
  71→    }
  72→
  73→    return numericPoints.length % 2 === 0
  74→        ? numericPoints
  75→        : numericPoints.slice(0, -1);
  76→};
  77→const getNameInitial = (name) => {
  78→    const normalizedName = typeof name === "string" ? name.trim() : "";
  79→    return normalizedName ? normalizedName.slice(0, 1).toUpperCase() : "?";
  80→};
  81→
  82→const useLoadedImage = (src) => {
  83→    const [image, setImage] = useState(null);
  84→
  85→    useEffect(() => {
  86→        if(!src){
  87→            setImage(null);
  88→            return;
  89→        }
  90→
  91→        const img = new window.Image();
  92→        img.crossOrigin = "anonymous";
  93→        img.onload = () => setImage(img);
  94→        img.onerror = () => setImage(null);
  95→        img.src = src;
  96→
  97→        return () => {
  98→            img.onload = null;
  99→            img.onerror = null;
 100→        };
 101→    }, [src]);
 102→
 103→    return image;
 104→};
