 596→    }, [clearQueuedDoodleBroadcast, currentUserProfile?.id, journalId, sendBroadcastEvent]);
 597→
 598→    useEffect(() => {
 599→        if(!journalId){
 600→            return;
 601→        }
 602→
 603→        const journalIdAsString = String(journalId);
 604→        const realtimeChannelName = `canvas-live-${journalIdAsString}-${Math.random().toString(36).slice(2, REALTIME_CHANNEL_SUFFIX_LENGTH + 2)}`;
 605→
 606→        const channel = supabase
 607→        .channel(realtimeChannelName)
 608→        .on(
 609→            "postgres_changes",
 610→            {event: "*", schema: "public", table: "canvas_stamps", filter: `journal_id=eq.${journalIdAsString}`},
 611→            (payload) => {
 612→                if(payload?.eventType === "DELETE"){
 613→                    if(payload?.old?.id){
 614→                        removeStampFromCache(payload.old.id);
 615→                    }
 616→                    return;
 617→                }
 618→
 619→                const nextStamp = normalizeStampRow(payload?.new);
 620→                if(nextStamp){
 621→                    upsertStampCache(nextStamp);
 622→                }
 623→            }
 624→        )
 625→        .on(
 626→            "postgres_changes",
 627→            {event: "DELETE", schema: "public", table: "canvas_stamps"},
 628→            (payload) => {
 629→                const match = eventBelongsToJournal(payload);
 630→                if(match === true && payload?.old?.id){
 631→                    removeStampFromCache(payload.old.id);
 632→                    return;
 633→                }
 634→
