130→const CanvasSurface = ({
131→    stageRef = null,
132→    viewportWidth,
133→    viewportHeight,
134→    stageWidth,
135→    stageHeight,
136→    fitScale = 1,
137→    fitOffsetX = 0,
138→    fitOffsetY = 0,
139→    viewport = {scale: 1, x: 0, y: 0},
140→    gridEnabled = false,
141→    theme = "light",
142→    doodles = [],
143→    isDrawing = false,
144→    currentDoodlePoints = [],
145→    doodleColor = DEFAULT_DOODLE_COLOR,
146→    doodleSize = 2.8,
147→    doodleStrokeScale = 1,
148→    sortedObjects = [],
149→    selectedObject = null,
150→    draggingObject = null,
151→    animatingRemovalId = null,
152→    canEditObjects = false,
153→    shouldPreventTouchDefault = false,
154→    activeTool = "select",
155→    className = "",
156→    children,
157→    onPointerDown,
158→    onPointerMove,
159→    onPointerUp,
160→    onStageClick,
161→    onStageTap,
162→    onSnippetSelect,
163→    onSnippetPress,
164→    onSnippetDragStart,
165→    onSnippetDragEnd,
166→    onImageSelect,
167→    onImagePress,
168→    onImageDragStart,
169→    onImageDragEnd
170→}) => {
171→    const layerTransform = useMemo(() => ({
172→        x: fitOffsetX + viewport.x,
173→        y: fitOffsetY + viewport.y,
174→        scaleX: fitScale * viewport.scale,
175→        scaleY: fitScale * viewport.scale
176→    }), [fitOffsetX, fitOffsetY, fitScale, viewport]);
177→
178→    return (
179→        <Stage
180→            ref={stageRef}
181→            width={viewportWidth}
182→            height={viewportHeight}
183→            preventDefault={activeTool === "doodle"}
184→            style={{touchAction: activeTool === "doodle" ? "none" : "pan-y"}}
185→            onMouseDown={onPointerDown}
186→            onTouchStart={onPointerDown}
187→            onMouseMove={onPointerMove}
188→            onTouchMove={onPointerMove}
189→            onMouseUp={onPointerUp}
190→            onTouchEnd={onPointerUp}
191→            onTouchCancel={onPointerUp}
192→            onMouseLeave={onPointerUp}
193→            onClick={onStageClick}
194→            onTap={onStageTap}
195→            className={className}
196→        >
197→            {gridEnabled && (
198→                <Layer listening={false} {...layerTransform} opacity={clamp((viewport.scale - 0.8) / 0.5, 0.15, 1)}>
199→                    {Array.from({length: Math.floor(stageWidth / GRID_SIZE) + 1}).map((_, index) => (
200→                        <Rect
201→                            key={`grid-v-${index}`}
202→                            x={index * GRID_SIZE}
203→                            y={0}
204→                            width={1}
205→                            height={stageHeight}
206→                            fill={theme === "dark" ? "rgba(235,235,235,0.08)" : "rgba(24,24,24,0.09)"}
207→                        />
208→                    ))}
209→                    {Array.from({length: Math.floor(stageHeight / GRID_SIZE) + 1}).map((_, index) => (
210→                        <Rect
211→                            key={`grid-h-${index}`}
212→                            x={0}
213→                            y={index * GRID_SIZE}
214→                            width={stageWidth}
215→                            height={1}
216→                            fill={theme === "dark" ? "rgba(235,235,235,0.08)" : "rgba(24,24,24,0.09)"}
217→                        />
218→                    ))}
219→                </Layer>
220→            )}
221→
222→            <Layer listening={false} {...layerTransform}>
223→                {doodles.map((doodle) => (
224→                    <Line
225→                        key={doodle.id}
226→                        points={(doodle.points || []).map((point, index) => (
227→                            index % 2 === 0 ? point * stageWidth : point * stageHeight
228→                        ))}
229→                        stroke={doodle.color || DEFAULT_DOODLE_COLOR}
230→                        strokeWidth={(Number(doodle.size) || 2.8) * doodleStrokeScale}
231→                        lineCap="round"
232→                        lineJoin="round"
233→                        tension={0.35}
234→                    />
235→                ))}
236→                {isDrawing && currentDoodlePoints.length >= 2 && (
237→                    <Line
238→                        points={currentDoodlePoints.map((point, index) => (
239→                            index % 2 === 0 ? point * stageWidth : point * stageHeight
240→                        ))}
241→                        stroke={doodleColor}
242→                        strokeWidth={doodleSize * doodleStrokeScale}
243→                        lineCap="round"
244→                        lineJoin="round"
245→                        tension={0.35}
246→                    />
247→                )}
248→            </Layer>
249→
250→            <Layer {...layerTransform}>
251→                {sortedObjects.map((object) => {
252→                    if(object.kind === "snippet"){
253→                        const snippet = object.payload;
254→                        const metrics = getSnippetMetrics(snippet, stageWidth);
255→                        const styleKey = FONT_STYLE_MAP[snippet.fontStyle] || "serif";
256→                        const brush = FONT_BRUSHES[styleKey] || FONT_BRUSHES.serif;
257→                        const snippetX = clamp(snippet.x * stageWidth, 0, Math.max(0, stageWidth - metrics.width));
258→                        const snippetY = clamp(snippet.y * stageHeight, 0, Math.max(0, stageHeight - metrics.height));
259→                        const isSelected = selectedObject?.kind === "snippet" && selectedObject?.id === snippet.id;
260→                        const isDragging = draggingObject?.kind === "snippet" && draggingObject?.id === snippet.id;
261→                        const liftMultiplier = isDragging ? OBJECT_LIFT_MULTIPLIER + 0.02 : isSelected ? OBJECT_LIFT_MULTIPLIER : 1;
262→                        const baseScaleX = snippet.scaleX === -1 ? -1 : 1;
263→
264→                        return (
265→                            <Text
266→                                key={snippet.id}
267→                                name={snippet.id}
268→                                x={snippetX}
269→                                y={snippetY}
270→                                width={metrics.width}
271→                                height={metrics.height}
272→                                text={snippet.text}
273→                                fontFamily={brush.fontFamily}
274→                                fontStyle={brush.fontStyle}
275→                                fontSize={metrics.fontSize}
276→                                fill={theme === "dark" ? "#f8f7f1" : "#151513"}
277→                                align="center"
278→                                verticalAlign="middle"
279→                                padding={8}
280→                                wrap="word"
281→                                draggable={canEditObjects}
282→                                rotation={snippet.rotation || 0}
283→                                scaleX={baseScaleX * liftMultiplier}
284→                                scaleY={liftMultiplier}
285→                                stroke={isSelected ? "#68d391" : "transparent"}
286→                                strokeWidth={isSelected ? 1.2 : 0}
287→                                preventDefault={shouldPreventTouchDefault}
288→                                shadowColor={theme === "dark" ? "rgba(0,0,0,0.58)" : "rgba(0,0,0,0.22)"}
289→                                shadowBlur={isSelected || isDragging ? 16 : 6}
290→                                shadowOffsetY={isSelected || isDragging ? 6 : 2}
291→                                onClick={(event) => {
292→                                    if(canEditObjects){
293→                                        onSnippetSelect?.(snippet, event);
294→                                    }
295→                                    onSnippetPress?.(snippet, event);
296→                                }}
297→                                onTap={(event) => {
298→                                    if(canEditObjects){
299→                                        onSnippetSelect?.(snippet, event);
300→                                    }
301→                                    onSnippetPress?.(snippet, event);
302→                                }}
303→                                onDragStart={canEditObjects ? ((event) => onSnippetDragStart?.(snippet, event)) : undefined}
304→                                onDragEnd={canEditObjects ? ((event) => onSnippetDragEnd?.(snippet, event)) : undefined}
305→                            />
306→                        );
307→                    }
308→
309→                    const image = object.payload;
310→                    const isSelected = selectedObject?.kind === "image" && selectedObject?.id === image.id;
311→                    const isDragging = draggingObject?.kind === "image" && draggingObject?.id === image.id;
312→                    return (
313→                        <CanvasImageNode
314→                            key={image.id}
315→                            canvasImage={image}
316→                            stageWidth={stageWidth}
317→                            stageHeight={stageHeight}
318→                            isSelected={isSelected}
319→                            isDragging={isDragging}
320→                            isBeingRemoved={animatingRemovalId === image.id}
321→                            canInteract={canEditObjects}
322→                            preventTouchDefault={shouldPreventTouchDefault}
323→                            onSelect={(event) => {
324→                                if(canEditObjects){
325→                                    onImageSelect?.(image, event);
326→                                }
327→                                onImagePress?.(image, event);
328→                            }}
329→                            onDragStart={canEditObjects ? ((event) => onImageDragStart?.(image, event)) : undefined}
330→                            onDragEnd={canEditObjects ? ((event) => onImageDragEnd?.(image, event)) : undefined}
331→                        />
332→                    );
333→                })}
334→            </Layer>
335→            {children}
336→        </Stage>
337→    );
338→};
