 51→const extractCanvasPlainText = (canvasDoc) => {
 52→    if(!canvasDoc || !Array.isArray(canvasDoc.snippets)){
 53→        return '';
 54→    }
 55→
 56→    return canvasDoc.snippets
 57→        .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text.trim() : ''))
 58→        .filter(Boolean)
 59→        .join(' ');
 60→}
